css:
.loader {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.loading svg polyline {
  fill: none;
  stroke-width: 3;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.loading svg polyline#uiverse-ecg-stroke-loader-back {
fill: none;
stroke: gray;
}

.loading svg polyline#uiverse-ecg-stroke-loader-front {
fill: none;
stroke: red;
stroke-dasharray: 48, 144;
stroke-dashoffset: 192;
animation: dash_682 1.4s linear infinite;
}

@keyframes dash_682 {
72.5% {
opacity: 0;
}

to {
stroke-dashoffset: 0;
}
}
